test_cases.python_test_script:
def test_tc_tcm_clutch_001(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert decode_clutch(msg) == 0

def test_tc_tcm_clutch_002(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert decode_clutch(msg) == 1

def test_tc_tcm_clutch_003(can_bus):
    msgs = [decode_clutch(can_bus.recv()) for _ in range(10)]
    assert 1 in msgs

def test_tc_tcm_clutch_004(can_bus):
    count = 0
    start = time.time()
    while time.time() - start < 2:
        if can_bus.recv(0.1).arbitration_id == 0x230: count += 1
    assert count > 1

def test_tc_tcm_clutch_005(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert decode_clutch(msg) == 0
